item.description:
1. 이진 검색   lt: 맨 왼쪽 / rt: 맨 오른쪽 / mid: lt와 rt의 중간
 arr의 mid 값이 condition() 함수의 조건 만족할때까지 검색
  while (lt &lt;= rt) { mid = Math.floor((lt + rt) / 2); if (condition(arr, mid) === false) { res = mid; lt = mid + 1; // mid는 이미 확인했기때문에 rt =&gt; mid - 1 / lt =&gt; mid + 1 } else rt = mid - 1; }

1. 소수 확인   n을 n의 제곱근 (Math.sqrt(n)) 까지 나눈 나머지가 0이 존재하면 안됨
 n이 소수면 true, 아니면 false 반환
  const chkPrime = (n) =&gt; { if (n === 0) return false; if (n === 1) return false; else if (n === 2) return true; else { for (let i = 2; i &lt;= Math.sqrt(n); i++) { if (n % i === 0) return false; } return true; } };

1. 조합   arr을 r 개 뽑는 모든 조합 res에 추가
 cnt 에 갯수 출력
  function combi(arr, r) { let res = []; let tmp = Array.from({ length: r }, () =&gt; 0); // let cnt = 0; function DFS(L, s) { if (L === r) { res.push(tmp.slice()); // cnt++; } else { for (let i = s; i &lt; arr.length; i++) { // s 부터 도는게 포인트 tmp[L] = arr[i]; DFS(L + 1, i + 1); // 다음 s 를 i + 1 로 세팅 } } } DFS(0, 0); // return cnt; return res; }

1. 중복 순열   arr 에서 중복을 허락하여 r 개 뽑아 res 에 추가
 cnt에 갯수 출력
  function arrPir(arr, r) { let res = []; let tmp = []; // let cnt = 0; function DFS(L) { if (L === r) { res.push(tmp.slice()); // cnt++; } else { for (let i = 0; i &lt; arr.length; i++) { // L차 순회하며 각 자리에 v 입력 tmp[L] = arr[i]; DFS(L + 1); } } } DFS(0); // return cnt; return res; }
